import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../../services/api';

function ApplyLeave({ user }) {
  const [leaveType, setLeaveType] = useState(''); // No default selection
  const [dateMode, setDateMode] = useState('single'); // 'single' or 'multiple'
  const [formData, setFormData] = useState({
    single_date: '',
    from_date: '',
    to_date: '',
    reason: ''
  });
  const [success, setSuccess] = useState(false);
  const [successMessage, setSuccessMessage] = useState('');
  const [error, setError] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const navigate = useNavigate();

  const handleLeaveTypeChange = (e) => {
    setLeaveType(e.target.value);
    setError('');
  };

  const handleDateModeChange = (mode) => {
    setDateMode(mode);
    setError('');
    // Clear date fields when switching modes
    setFormData({
      ...formData,
      single_date: '',
      from_date: '',
      to_date: ''
    });
  };

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const validateForm = () => {
    if (!leaveType) {
      setError('Please select a leave type');
      return false;
    }

    if (dateMode === 'single') {
      if (!formData.single_date) {
        setError('Please select a date');
        return false;
      }
    } else {
      if (!formData.from_date || !formData.to_date) {
        setError('Please select both from and to dates');
        return false;
      }
      if (formData.from_date > formData.to_date) {
        setError('From date cannot be after to date');
        return false;
      }
    }

    if (!formData.reason.trim()) {
      setError('Please enter a reason');
      return false;
    }

    return true;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!validateForm()) {
      return;
    }

    setSubmitting(true);
    setError('');
    setSuccess(false);
    
    try {
      const leaveData = {
        leave_type: leaveType,
        reason: formData.reason
      };

      if (dateMode === 'single') {
        leaveData.date = formData.single_date;
      } else {
        leaveData.from_date = formData.from_date;
        leaveData.to_date = formData.to_date;
      }
      
      const response = await api.post('/leave/', leaveData);
      
      // Handle response
      if (response.data.message) {
        setSuccessMessage(response.data.message);
      } else {
        const dayCount = dateMode === 'single' ? 1 : 
          Math.ceil((new Date(formData.to_date) - new Date(formData.from_date)) / (1000 * 60 * 60 * 24)) + 1;
        setSuccessMessage(`${dayCount} leave day(s) applied successfully!`);
      }
      
      setSuccess(true);
      
      // Clear form
      setLeaveType('');
      setFormData({ 
        single_date: '', 
        from_date: '', 
        to_date: '', 
        reason: '' 
      });

      // Redirect to dashboard after 2 seconds
      setTimeout(() => {
        if (user.is_admin) {
          navigate('/admin');
        } else {
          navigate('/dashboard');
        }
      }, 2000);
      
    } catch (err) {
      console.error('Leave application error:', err.response?.data);
      setError(err.response?.data?.error || 'Failed to apply leave');
    } finally {
      setSubmitting(false);
    }
  };

  const handleBack = () => {
    if (user.is_admin) {
      navigate('/admin');
    } else {
      navigate('/dashboard');
    }
  };

  const today = new Date().toISOString().split('T')[0];

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h2 style={styles.title}>Apply Leave</h2>
        
        {success && (
          <div style={styles.success}>
            <div style={styles.successIcon}>✓</div>
            <div style={styles.successMessage}>{successMessage}</div>
            <div style={styles.redirect}>Redirecting to dashboard...</div>
          </div>
        )}
        
        {error && (
          <div style={styles.error}>
            <div style={styles.errorIcon}>!</div>
            <div style={styles.errorMessage}>{error}</div>
          </div>
        )}
        
        <form onSubmit={handleSubmit} style={styles.form}>
          {/* Leave Type Dropdown - No default selection */}
          <div style={styles.formGroup}>
            <label style={styles.label}>
              Leave Type <span style={styles.required}>*</span>
            </label>
            <select 
              name="leave_type" 
              value={leaveType}
              onChange={handleLeaveTypeChange}
              style={{
                ...styles.select,
                ...(leaveType === '' ? styles.selectPlaceholder : {})
              }}
              required
              disabled={success}
            >
              <option value="" disabled>-- Select Leave Type --</option>
              <option value="SL">Sick Leave</option>
              <option value="PL">Paid Leave</option>
              <option value="CL">Casual Leave</option>
            </select>
          </div>
          
          {/* Toggle for Single/Multiple Days */}
          <div style={styles.formGroup}>
            <label style={styles.label}>Leave Duration</label>
            <div style={styles.toggleGroup}>
              <button 
                type="button" 
                onClick={() => handleDateModeChange('single')}
                disabled={success}
                style={{
                  ...styles.toggleButton,
                  ...(dateMode === 'single' ? styles.toggleButtonActive : {}),
                  ...(success ? styles.disabledButton : {})
                }}
              >
                Single Day
              </button>
              <button 
                type="button" 
                onClick={() => handleDateModeChange('multiple')}
                disabled={success}
                style={{
                  ...styles.toggleButton,
                  ...(dateMode === 'multiple' ? styles.toggleButtonActive : {}),
                  ...(success ? styles.disabledButton : {})
                }}
              >
                Multiple Days
              </button>
            </div>
          </div>
          
          {/* Date Selection based on mode */}
          {dateMode === 'single' ? (
            <div style={styles.formGroup}>
              <label style={styles.label}>
                Date <span style={styles.required}>*</span>
              </label>
              <input 
                type="date"  
                name="single_date"  
                value={formData.single_date}  
                onChange={handleChange}  
                min={today}  
                style={styles.input} 
                required
                disabled={success}
              />
            </div>
          ) : (
            <>
              <div style={styles.formRow}>
                <div style={styles.formGroupHalf}>
                  <label style={styles.label}>
                    From <span style={styles.required}>*</span>
                  </label>
                  <input 
                    type="date"  
                    name="from_date"  
                    value={formData.from_date}  
                    onChange={handleChange}  
                    min={today} 
                    style={styles.input}  
                    required
                    disabled={success}
                  />
                </div>
                
                <div style={styles.formGroupHalf}>
                  <label style={styles.label}>
                    To <span style={styles.required}>*</span>
                  </label>
                  <input  
                    type="date" 
                    name="to_date"  
                    value={formData.to_date}  
                    onChange={handleChange}  
                    min={formData.from_date || today}  
                    style={styles.input}  
                    required
                    disabled={success}
                  />
                </div>
              </div>
              
              {formData.from_date && formData.to_date && !error && (
                <div style={styles.dateRangeInfo}>
                  Selected: {new Date(formData.from_date).toLocaleDateString()} to {new Date(formData.to_date).toLocaleDateString()}
                  {formData.from_date <= formData.to_date && (
                    <span style={styles.dayCount}>
                      ({Math.ceil((new Date(formData.to_date) - new Date(formData.from_date)) / (1000 * 60 * 60 * 24)) + 1} days)
                    </span>
                  )}
                </div>
              )}
            </>
          )}
          
          {/* Reason Textarea */}
          <div style={styles.formGroup}>
            <label style={styles.label}>
              Reason <span style={styles.required}>*</span>
            </label>
            <textarea  
              name="reason"  
              value={formData.reason}  
              onChange={handleChange}  
              rows="4"  
              style={styles.textarea}
              required
              disabled={success}
              placeholder="Enter detailed reason for leave..."
            />
          </div>
          
          {/* Submit Button */}
          <button 
            type="submit" 
            disabled={submitting || success || !leaveType}
            style={(submitting || success || !leaveType) ? styles.disabledButton : styles.submitButton}
          >
            {submitting ? (
              <span style={styles.buttonContent}>
                <span style={styles.spinner}></span>
                Applying...
              </span>
            ) : success ? (
              <span style={styles.buttonContent}>
                <span style={styles.checkmark}>✓</span>
                Applied
              </span>
            ) : (
              'Apply Leave'
            )}
          </button>
        </form>
        
        {/* Back Button */}
        <button 
          onClick={handleBack} 
          style={success ? styles.disabledButton : styles.backButton}
          disabled={success}
        >
          ← Back to Dashboard
        </button>
      </div>
    </div>
  );
}

const styles = {
  container: {
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    minHeight: '100vh',
    padding: '20px',
    backgroundColor: 'var(--moss-light)',
  },
  card: {
    background: 'white',
    padding: '35px',
    borderRadius: '20px',
    width: '450px',
    maxWidth: '100%',
    boxShadow: '0 10px 30px rgba(0,0,0,0.2)',
    border: '2px solid var(--moss-green)',
  },
  title: {
    color: 'var(--moss-dark)',
    fontSize: '28px',
    marginTop: 0,
    marginBottom: '25px',
    textAlign: 'center',
    fontWeight: 600,
    borderBottom: '2px solid var(--moss-light)',
    paddingBottom: '15px',
  },
  form: {
    display: 'flex',
    flexDirection: 'column',
  },
  formGroup: {
    marginBottom: '20px',
  },
  formRow: {
    display: 'flex',
    gap: '15px',
    marginBottom: '5px',
  },
  formGroupHalf: {
    flex: 1,
    marginBottom: '15px',
  },
  label: {
    display: 'block',
    marginBottom: '8px',
    color: 'var(--moss-dark)',
    fontSize: '16px',
    fontWeight: 600,
  },
  required: {
    color: '#d32f2f',
    marginLeft: '4px',
  },
  input: {
    width: '100%',
    padding: '12px',
    border: '2px solid var(--moss-light)',
    borderRadius: '10px',
    fontSize: '15px',
    fontFamily: 'Times New Roman, Times, serif',
    boxSizing: 'border-box',
    transition: 'border-color 0.2s',
    outline: 'none',
    ':focus': {
      borderColor: 'var(--moss-green)',
    },
  },
  select: {
    width: '100%',
    padding: '12px',
    border: '2px solid var(--moss-light)',
    borderRadius: '10px',
    fontSize: '15px',
    fontFamily: 'Times New Roman, Times, serif',
    boxSizing: 'border-box',
    backgroundColor: 'white',
    cursor: 'pointer',
    outline: 'none',
  },
  selectPlaceholder: {
    color: '#999',
  },
  textarea: {
    width: '100%',
    padding: '12px',
    border: '2px solid var(--moss-light)',
    borderRadius: '10px',
    fontSize: '15px',
    fontFamily: 'Times New Roman, Times, serif',
    boxSizing: 'border-box',
    resize: 'vertical',
    minHeight: '100px',
    outline: 'none',
  },
  toggleGroup: {
    display: 'flex',
    gap: '10px',
    marginTop: '5px',
  },
  toggleButton: {
    flex: 1,
    padding: '12px',
    backgroundColor: 'white',
    color: 'var(--moss-dark)',
    border: '2px solid var(--moss-light)',
    borderRadius: '10px',
    cursor: 'pointer',
    fontSize: '15px',
    fontFamily: 'Times New Roman, Times, serif',
    transition: 'all 0.2s',
    fontWeight: 500,
  },
  toggleButtonActive: {
    backgroundColor: 'var(--moss-green)',
    color: 'white',
    borderColor: 'var(--moss-dark)',
  },
  dateRangeInfo: {
    fontSize: '14px',
    color: 'var(--moss-dark)',
    marginTop: '5px',
    marginBottom: '15px',
    padding: '8px',
    backgroundColor: 'var(--moss-pale)',
    borderRadius: '8px',
    textAlign: 'center',
  },
  dayCount: {
    fontWeight: 'bold',
    marginLeft: '8px',
    color: 'var(--moss-green)',
  },
  submitButton: {
    width: '100%',
    padding: '14px',
    margin: '10px 0 10px',
    backgroundColor: 'var(--moss-green)',
    color: 'white',
    border: 'none',
    borderRadius: '10px',
    cursor: 'pointer',
    fontSize: '18px',
    fontWeight: 'bold',
    fontFamily: 'Times New Roman, Times, serif',
    transition: 'background-color 0.2s',
    ':hover': {
      backgroundColor: 'var(--moss-dark)',
    },
  },
  disabledButton: {
    width: '100%',
    padding: '14px',
    margin: '10px 0 10px',
    backgroundColor: '#cccccc',
    color: '#666666',
    border: 'none',
    borderRadius: '10px',
    fontSize: '18px',
    fontFamily: 'Times New Roman, Times, serif',
    cursor: 'not-allowed',
  },
  backButton: {
    width: '100%',
    padding: '12px',
    backgroundColor: 'transparent',
    color: 'var(--moss-dark)',
    border: '2px solid var(--moss-green)',
    borderRadius: '10px',
    cursor: 'pointer',
    fontSize: '16px',
    fontFamily: 'Times New Roman, Times, serif',
    marginTop: '5px',
    transition: 'all 0.2s',
    ':hover': {
      backgroundColor: 'var(--moss-pale)',
    },
  },
  buttonContent: {
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    gap: '8px',
  },
  spinner: {
    width: '18px',
    height: '18px',
    border: '3px solid #ffffff',
    borderTop: '3px solid transparent',
    borderRadius: '50%',
    animation: 'spin 1s linear infinite',
  },
  checkmark: {
    fontSize: '20px',
    fontWeight: 'bold',
  },
  success: {
    backgroundColor: '#d4edda',
    color: '#155724',
    padding: '15px',
    borderRadius: '10px',
    marginBottom: '20px',
    textAlign: 'center',
    border: '2px solid #c3e6cb',
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
  },
  successIcon: {
    width: '40px',
    height: '40px',
    backgroundColor: '#28a745',
    color: 'white',
    borderRadius: '50%',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    fontSize: '24px',
    marginBottom: '10px',
  },
  successMessage: {
    fontSize: '16px',
    fontWeight: 'bold',
    marginBottom: '5px',
  },
  redirect: {
    fontSize: '14px',
    color: '#28a745',
  },
  error: {
    backgroundColor: '#f8d7da',
    color: '#721c24',
    padding: '15px',
    borderRadius: '10px',
    marginBottom: '20px',
    border: '2px solid #f5c6cb',
    display: 'flex',
    alignItems: 'center',
    gap: '10px',
  },
  errorIcon: {
    width: '24px',
    height: '24px',
    backgroundColor: '#dc3545',
    color: 'white',
    borderRadius: '50%',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    fontSize: '16px',
    fontWeight: 'bold',
    flexShrink: 0,
  },
  errorMessage: {
    fontSize: '15px',
  },
};

// Add keyframe animation for spinner
const styleSheet = document.createElement("style");
styleSheet.textContent = `
  @keyframes spin {
    0% { transform: rotate(0deg); }
    100% { transform: rotate(360deg); }
  }
`;
document.head.appendChild(styleSheet);

export default ApplyLeave;
